3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type Item = {
5	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const INSURANCE_SURCHARGE_RATE = 0.1;
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PRICE = 60;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	
27	function componentBasePremium(count: number, unitPrice: number): number {
28	  return count === COMPONENT_BLOCK_SIZE
29	    ? COMPONENT_BLOCK_PRICE
30	    : count * unitPrice;
31	}
32	
33	function itemsBasePremium(items: Item[]): number {
34	  const componentCounts: Record<string, number> = {};
35	  let nonComponentBase = 0;
36	  for (const item of items) {
37	    if (COMPONENT_TYPES.has(item.type)) {
38	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
39	    } else {
40	      nonComponentBase += BASE_PREMIUMS[item.type];
41	    }
42	  }
43	  const componentBase = Object.entries(componentCounts).reduce(
44	    (total, [type, count]) =>
45	      total + componentBasePremium(count, BASE_PREMIUMS[type]),
46	    0
47	  );
48	  return nonComponentBase + componentBase;
49	}
50	
51	export function quote(_customer: Customer, items: Item[]): number {
52	  const itemsBase = itemsBasePremium(items);
53	  const insuranceSurcharge = itemsBase * INSURANCE_SURCHARGE_RATE;
54	  return Math.ceil(itemsBase + insuranceSurcharge + PROCESSING_FEE);
55	}
